class Solution {
public:
    int maxSubstrings(string word) {
        int n = word.size();
        int res = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 3; j < n; j++) {
                if (word[i] == word[j] && isMatch(word, i + 1, j - 1)) {
                    res++;
                }
            }
        }
        return res;
    }

    bool isMatch(string word, int start, int end) {
        while (start <= end) {
            if (word[start] != word[end]) return false;
            start++;
            end--;
        }
        return true;
    }
};
```

